import { useState, useEffect, useCallback, useRef } from 'react';
import { api, apiPost, apiDelete } from '../utils/api';

export default function useAlerts() {
  const [alerts, setAlerts] = useState([]);
  const [triggered, setTriggered] = useState([]);
  const [loading, setLoading] = useState(true);
  const hasLoaded = useRef(false);

  const refresh = useCallback(async () => {
    if (!hasLoaded.current) setLoading(true);
    const [alertsData, triggeredData] = await Promise.all([
      api('/alerts'),
      api('/alerts/triggered'),
    ]);

    if (alertsData) {
      const arr = Array.isArray(alertsData) ? alertsData : alertsData.alerts;
      setAlerts(Array.isArray(arr) ? arr : []);
    }
    if (triggeredData) {
      const arr = Array.isArray(triggeredData) ? triggeredData : triggeredData.triggered;
      setTriggered(Array.isArray(arr) ? arr : []);
    }
    setLoading(false);
    hasLoaded.current = true;
  }, []);

  useEffect(() => {
    refresh();
    const interval = setInterval(refresh, 15000);
    return () => clearInterval(interval);
  }, [refresh]);

  const createAlert = useCallback(async (data) => {
    const created = await apiPost('/alerts', data);
    if (created) { await refresh(); return created; }
    return null;
  }, [refresh]);

  const deleteAlert = useCallback(async (id) => {
    const result = await apiDelete('/alerts/' + id);
    if (result) { await refresh(); return true; }
    return false;
  }, [refresh]);

  return { alerts, triggered, loading, createAlert, deleteAlert, refresh, fetchAlerts: refresh };
}
